    private boolean verifySignature(String timestampValue, String signature) throws Exception {
        byte[] keyBytes = Base64.getDecoder().decode((String) smc.getMessageContext().get(Scope.MESSAGE_CONTEXT).getProperty("wsse:SecurityToken"));
        SecretKeySpec secretKey = new SecretKeySpec(keyBytes, "HmacSHA1");

        Mac mac = Mac.getInstance("HmacSHA1");
        mac.init(secretKey);
        byte[] digest = mac.doFinal(timestampValue.getBytes());

        String expectedSignature = Base64.getEncoder().encodeToString(digest);

        return signature.equals(expectedSignature);
    }
